from django import forms, http
from django.contrib import auth
from django.shortcuts import redirect, render
import base64, datetime
try:
    from urllib2 import urlopen
except ImportError as e:
    try:
        from urllib.request import urlopen  # py3k.
    except Exception:
        raise ImportError("The Python URL handling modules must be installed.")


class LoginForm(forms.Form):

    username = forms.CharField()
    password = forms.CharField(widget=forms.PasswordInput)


def login_view(request):

    if request.user.is_authenticated():

        return redirect('index')
    
    form = LoginForm(data=request.POST or None, auto_id='login_%s',
                     initial={'username': 'admin'})
    if not form.is_valid() and 'next' in request.GET:
        next = request.GET['next']

    if request.method == 'POST' and form.is_valid():

        try:

            auth.authenticate(
                request, username=form.cleaned_data['username'], password=form.cleaned_data['password'])

        except Exception as e:
            
            return render(request, 'login/login.html',
                          {'next': next,
                           'form': form})
        
        # Check to make sure that the user has all the permissions needed to log in.

        try:

            auth.login(request, auth.authenticate(
                request, username=form.cleaned_data['username'], password=form.cleaned_data['password']))

        except Exception as e:
            
            return render(request, 'login/login.html',
                          {'next': next,
                           'form': form})
        
        try:

            if 'next' in request.GET and not request.GET["next"].startswith("/login"):
                return redirect(request.GET['next'])

            else:

                return redirect('index')

        except Exception as e:
            
            pass

    return render(request, 'login/login.html', {'form': form})


def logout_view(request):
    auth.logout(request)
    if not request.user.is_authenticated():
        try:
            return http.HttpResponseRedirect('index')
        except Exception as e:
            pass
    return redirect('index')